'use client'

import { useEffect } from 'react'
import { useRouter } from 'next/navigation'
import { supabase } from '@/lib/supabase'

export default function AuthCallback() {
  const router = useRouter()

  useEffect(() =&gt; {
    const finishAuth = async () =&gt; {
      await supabase.auth.getSession()
      router.replace('/')
    }

    finishAuth()
  }, [router])

  return (
    &lt;div className="flex min-h-screen items-center justify-center"&gt;
      جاري تأكيد البريد...
    &lt;/div&gt;
  )
}

'use client';

import { useState } from 'react';
import { useRouter } from 'next/navigation';
import { supabase } from '@/lib/supabase';
import { Button } from '@/components/ui/button';
import { Input } from '@/components/ui/input';
import { Label } from '@/components/ui/label';
import { Card, CardContent, CardDescription, CardHeader, CardTitle } from '@/components/ui/card';
import { FormAlert } from '@/components/ui/form-alert';
import { ArrowRight, Sparkles } from 'lucide-react';
import Link from 'next/link';

export default function ForgotPasswordPage() {
  const [email, setEmail] = useState('');
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState('');
  const [success, setSuccess] = useState(false);
  const router = useRouter();

  const handleSubmit = async (e: React.FormEvent) =&gt; {
    e.preventDefault();
    setLoading(true);
    setError('');
    setSuccess(false);

    const { error } = await supabase.auth.resetPasswordForEmail(email, {
      redirectTo: `${window.location.origin}/auth/reset-password`,
    });

    if (error) {
      setError('حدث خطأ. يرجى التأكد من البريد الإلكتروني والمحاولة مرة أخرى.');
    } else {
      setSuccess(true);
    }

    setLoading(false);
  };

  return (
    &lt;div className="min-h-screen flex items-center justify-center p-4 bg-gradient-to-br from-purple-900/20 to-background"&gt;
      &lt;Card className="w-full max-w-md border-purple-500/20"&gt;
        &lt;CardHeader className="text-center space-y-2"&gt;
          &lt;div className="flex justify-center mb-4"&gt;
            &lt;div className="p-3 bg-gradient-purple rounded-2xl"&gt;
              &lt;Sparkles className="h-8 w-8 text-white" /&gt;
            &lt;/div&gt;
          &lt;/div&gt;
          &lt;CardTitle className="text-3xl font-bold text-gradient"&gt;استعادة كلمة المرور&lt;/CardTitle&gt;
          &lt;CardDescription className="text-base"&gt;
            أدخل بريدك الإلكتروني لإرسال رابط استعادة كلمة المرور
          &lt;/CardDescription&gt;
        &lt;/CardHeader&gt;
        &lt;CardContent&gt;
          {success ? (
            &lt;div className="space-y-4"&gt;
              &lt;FormAlert
                type="success"
                message="تم إرسال رابط استعادة كلمة المرور إلى بريدك الإلكتروني. يرجى التحقق من صندوق الوارد."
              /&gt;
              &lt;Button
                onClick={() =&gt; router.push('/auth/login')}
                className="w-full gradient-purple"
              &gt;
                &lt;ArrowRight className="h-4 w-4 ml-2" /&gt;
                العودة لتسجيل الدخول
              &lt;/Button&gt;
            &lt;/div&gt;
          ) : (
            &lt;form onSubmit={handleSubmit} className="space-y-4"&gt;
              &lt;div className="space-y-2"&gt;
                &lt;Label htmlFor="email"&gt;البريد الإلكتروني&lt;/Label&gt;
                &lt;Input
                  id="email"
                  type="email"
                  value={email}
                  onChange={(e) =&gt; setEmail(e.target.value)}
                  required
                  className="text-right"
                  placeholder="email@example.com"
                /&gt;
              &lt;/div&gt;

              {error &amp;&amp; &lt;FormAlert type="error" message={error} /&gt;}

              &lt;Button
                type="submit"
                disabled={loading}
                className="w-full gradient-purple"
              &gt;
                {loading ? 'جاري الإرسال...' : 'إرسال رابط الاستعادة'}
              &lt;/Button&gt;

              &lt;Link
                href="/auth/login"
                className="flex items-center justify-center gap-2 text-sm text-muted-foreground hover:text-purple-400"
              &gt;
                &lt;ArrowRight className="h-4 w-4" /&gt;
                العودة لتسجيل الدخول
              &lt;/Link&gt;
            &lt;/form&gt;
          )}
        &lt;/CardContent&gt;
      &lt;/Card&gt;
    &lt;/div&gt;
  );
}

'use client';

import { useState } from 'react';
import { useRouter } from 'next/navigation';
import { supabase } from '@/lib/supabase';
import { Button } from '@/components/ui/button';
import { Input } from '@/components/ui/input';
import { Label } from '@/components/ui/label';
import { Card, CardContent, CardDescription, CardHeader, CardTitle } from '@/components/ui/card';
import { FormAlert } from '@/components/ui/form-alert';
import { Sparkles } from 'lucide-react';
import Link from 'next/link';

export default function LoginPage() {
  const [identifier, setIdentifier] = useState('');
  const [password, setPassword] = useState('');
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState('');
  const router = useRouter();

  const handleLogin = async (e: React.FormEvent) =&gt; {
  e.preventDefault();
  setLoading(true);
  setError('');
  const isEmail = identifier.includes('@');

  // تحويل username → email
  const { data: email, error: rpcError } = await supabase.rpc(
    'get_email_from_identifier',
    { identifier }
  );

  if (rpcError || !email) {
    setError('البريد الإلكتروني أو اسم المستخدم غير صحيح');
    setLoading(false);
    return;
  }

  const { error } = await supabase.auth.signInWithPassword({
    email,
    password,
  });

  if (error) {
    setError('البريد الإلكتروني أو كلمة المرور غير صحيحة');
    setLoading(false);
    return;
  }

  router.push('/');
  setLoading(false);
};

  return (
    &lt;div className="min-h-screen flex items-center justify-center p-4 bg-gradient-to-br from-purple-900/20 to-background"&gt;
      &lt;Card className="w-full max-w-md border-purple-500/20"&gt;
        &lt;CardHeader className="text-center space-y-2"&gt;
          &lt;div className="flex justify-center mb-4"&gt;
            &lt;div className="p-3 bg-gradient-purple rounded-2xl"&gt;
              &lt;Sparkles className="h-8 w-8 text-white" /&gt;
            &lt;/div&gt;
          &lt;/div&gt;
          &lt;CardTitle className="text-3xl font-bold text-gradient"&gt;استلهم&lt;/CardTitle&gt;
          &lt;CardDescription className="text-base"&gt;
            مرحباً بك مجدداً في منصة المصممين
          &lt;/CardDescription&gt;
        &lt;/CardHeader&gt;
        &lt;CardContent&gt;
          &lt;form onSubmit={handleLogin} className="space-y-4"&gt;
            &lt;div className="space-y-2"&gt;
              &lt;Label htmlFor="identifier"&gt;البريد الإلكتروني أو اسم المستخدم&lt;/Label&gt;
&lt;Input
  id="identifier"
  type="text"
  value={identifier}
  onChange={(e) =&gt; setIdentifier(e.target.value)}
  required
  className="text-right"
  placeholder="البريد الإلكتروني أو اسم المستخدم"
/&gt;
            &lt;/div&gt;

            &lt;div className="space-y-2"&gt;
              &lt;Label htmlFor="password"&gt;كلمة المرور&lt;/Label&gt;
              &lt;Input
                id="password"
                type="password"
                value={password}
                onChange={(e) =&gt; setPassword(e.target.value)}
                required
                className="text-right"
                placeholder="••••••••"
              /&gt;
            &lt;/div&gt;

            {error &amp;&amp; &lt;FormAlert type="error" message={error} /&gt;}

            &lt;Button
              type="submit"
              disabled={loading}
              className="w-full gradient-purple hover:opacity-90"
            &gt;
              {loading ? 'جاري تسجيل الدخول...' : 'تسجيل الدخول'}
            &lt;/Button&gt;

            &lt;div className="flex flex-col gap-2"&gt;
              &lt;Link
                href="/auth/forgot-password"
                className="text-center text-sm text-purple-400 hover:text-purple-300"
              &gt;
                نسيت كلمة المرور؟
              &lt;/Link&gt;
            &lt;/div&gt;

            &lt;div className="pt-4 border-t border-border space-y-2"&gt;
              &lt;p className="text-center text-sm text-muted-foreground"&gt;
                ليس لديك حساب؟{' '}
                &lt;Link href="/auth/signup" className="text-purple-400 hover:text-purple-300"&gt;
                  إنشاء حساب جديد
                &lt;/Link&gt;
              &lt;/p&gt;

              &lt;div className="flex justify-center gap-4 text-xs text-muted-foreground"&gt;
                &lt;Link href="/support" className="hover:text-purple-400"&gt;
                  الدعم والمساعدة
                &lt;/Link&gt;
                &lt;span&gt;•&lt;/span&gt;
                &lt;Link href="/platform-news" className="hover:text-purple-400"&gt;
                  أخبار المنصة
                &lt;/Link&gt;
              &lt;/div&gt;
            &lt;/div&gt;
          &lt;/form&gt;
        &lt;/CardContent&gt;
      &lt;/Card&gt;
    &lt;/div&gt;
  );
}

'use client';

import { useState } from 'react';
import { supabase } from '@/lib/supabase';
import { Button } from '@/components/ui/button';
import { Input } from '@/components/ui/input';
import { Label } from '@/components/ui/label';
import { Card, CardContent, CardDescription, CardHeader, CardTitle } from '@/components/ui/card';
import { Sparkles, Mail, CircleCheck as CheckCircle } from 'lucide-react';
import Link from 'next/link';

export default function ResetPasswordPage() {
  const [email, setEmail] = useState('');
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState('');
  const [success, setSuccess] = useState(false);

  const handleReset = async (e: React.FormEvent) =&gt; {
    e.preventDefault();
    setLoading(true);
    setError('');

    const { error: resetError } = await supabase.auth.resetPasswordForEmail(email, {
      redirectTo: `${window.location.origin}/auth/update-password`,
    });

    if (resetError) {
      setError(resetError.message);
      setLoading(false);
      return;
    }

    setSuccess(true);
    setLoading(false);
  };

  if (success) {
    return (
      &lt;div className="min-h-screen flex items-center justify-center p-4 bg-gradient-to-br from-purple-900/20 to-background"&gt;
        &lt;Card className="w-full max-w-md border-purple-500/20"&gt;
          &lt;CardContent className="py-12 text-center space-y-4"&gt;
            &lt;CheckCircle className="h-16 w-16 mx-auto text-green-500" /&gt;
            &lt;h2 className="text-2xl font-bold"&gt;تم الإرسال بنجاح&lt;/h2&gt;
            &lt;p className="text-muted-foreground"&gt;
              تم إرسال رابط إعادة تعيين كلمة المرور إلى بريدك الإلكتروني
            &lt;/p&gt;
            &lt;p className="text-sm text-muted-foreground"&gt;
              يرجى التحقق من بريدك الإلكتروني واتباع التعليمات
            &lt;/p&gt;
            &lt;Link href="/auth/login"&gt;
              &lt;Button className="gradient-purple mt-4"&gt;
                العودة لتسجيل الدخول
              &lt;/Button&gt;
            &lt;/Link&gt;
          &lt;/CardContent&gt;
        &lt;/Card&gt;
      &lt;/div&gt;
    );
  }

  return (
    &lt;div className="min-h-screen flex items-center justify-center p-4 bg-gradient-to-br from-purple-900/20 to-background"&gt;
      &lt;Card className="w-full max-w-md border-purple-500/20"&gt;
        &lt;CardHeader className="text-center space-y-2"&gt;
          &lt;div className="flex justify-center mb-4"&gt;
            &lt;div className="p-3 bg-gradient-purple rounded-2xl"&gt;
              &lt;Sparkles className="h-8 w-8 text-white" /&gt;
            &lt;/div&gt;
          &lt;/div&gt;
          &lt;CardTitle className="text-3xl font-bold text-gradient"&gt;استعادة كلمة المرور&lt;/CardTitle&gt;
          &lt;CardDescription className="text-base"&gt;
            أدخل بريدك الإلكتروني لاستعادة كلمة المرور
          &lt;/CardDescription&gt;
        &lt;/CardHeader&gt;
        &lt;CardContent&gt;
          &lt;form onSubmit={handleReset} className="space-y-4"&gt;
            &lt;div className="space-y-2"&gt;
              &lt;Label htmlFor="email"&gt;البريد الإلكتروني&lt;/Label&gt;
              &lt;div className="relative"&gt;
                &lt;Mail className="absolute right-3 top-1/2 -translate-y-1/2 h-4 w-4 text-muted-foreground" /&gt;
                &lt;Input
                  id="email"
                  type="email"
                  value={email}
                  onChange={(e) =&gt; setEmail(e.target.value)}
                  required
                  className="text-right pr-10"
                  placeholder="email@example.com"
                /&gt;
              &lt;/div&gt;
            &lt;/div&gt;

            {error &amp;&amp; (
              &lt;div className="p-3 rounded-lg bg-destructive/10 border border-destructive/20 text-destructive text-sm text-center"&gt;
                {error}
              &lt;/div&gt;
            )}

            &lt;Button
              type="submit"
              disabled={loading}
              className="w-full gradient-purple"
            &gt;
              {loading ? 'جاري الإرسال...' : 'إرسال رابط الاستعادة'}
            &lt;/Button&gt;

            &lt;div className="text-center text-sm"&gt;
              &lt;Link
                href="/auth/login"
                className="text-purple-400 hover:text-purple-300"
              &gt;
                العودة لتسجيل الدخول
              &lt;/Link&gt;
            &lt;/div&gt;
          &lt;/form&gt;
        &lt;/CardContent&gt;
      &lt;/Card&gt;
    &lt;/div&gt;
  );
}

'use client';

import { useState, useEffect } from 'react';
import { useRouter } from 'next/navigation';
import { supabase } from '@/lib/supabase';
import { Button } from '@/components/ui/button';
import { Input } from '@/components/ui/input';
import { Label } from '@/components/ui/label';
import { Card, CardContent, CardDescription, CardHeader, CardTitle } from '@/components/ui/card';
import { Sparkles, Check, X, Loader as Loader2 } from 'lucide-react';
import Link from 'next/link';

export default function SignupPage() {
  const [email, setEmail] = useState('');
  const [password, setPassword] = useState('');
  const [username, setUsername] = useState('');
  const [accountType, setAccountType] = useState&lt;'designer' | 'seeker' | 'general'&gt;('general');
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState('');
  const [usernameAvailable, setUsernameAvailable] = useState&lt;boolean | null&gt;(null);
  const [checkingUsername, setCheckingUsername] = useState(false);
  const router = useRouter();

  useEffect(() =&gt; {
    const checkUsername = async () =&gt; {
      if (username.length &lt; 3) {
        setUsernameAvailable(null);
        return;
      }
const usernameRegex = /^[a-zA-Z0-9_]+$/;

if (!usernameRegex.test(username)) {
  setUsernameAvailable(false);
  return;
}
      setCheckingUsername(true);

      const [reservedRes, existingRes] = await Promise.all([
        supabase.from('reserved_usernames').select('id').eq('username', username.toLowerCase()).maybeSingle(),
        supabase.from('profiles').select('id').eq('username', username.toLowerCase()).maybeSingle(),
      ]);

      const available = !reservedRes.data &amp;&amp; !existingRes.data;
      setUsernameAvailable(available);
      setCheckingUsername(false);
    };

    const debounce = setTimeout(checkUsername, 500);
    return () =&gt; clearTimeout(debounce);
  }, [username]);

const handleSignup = async (e: React.FormEvent) =&gt; {
  e.preventDefault();
  setLoading(true);
  setError('');

// الحد الأقصى لطول اسم المستخدم
if (username.length &gt; 25) {
  setError('اسم المستخدم يجب ألا يتجاوز 25 حرفاً');
  setLoading(false);
  return;
}

// السماح بالحروف الإنجليزية والأرقام والشرطة السفلية فقط
const usernameRegex = /^[a-z0-9_]+$/;

if (!usernameRegex.test(username)) {
  setError('اسم المستخدم يسمح بالحروف الإنجليزية والأرقام والشرطة السفلية فقط');
  setLoading(false);
  return;
}

  // التحقق هل الاسم محجوز
  const { data: reserved } = await supabase
    .from('reserved_usernames')
    .select('id')
    .eq('username', username.toLowerCase())
    .maybeSingle();

  if (reserved) {
    setError('اسم المستخدم غير متاح للتسجيل');
    setLoading(false);
    return;
  }

  // التحقق هل الاسم مستخدم
  const { data: existing } = await supabase
    .from('profiles')
    .select('id')
    .eq('username', username.toLowerCase())
    .maybeSingle();

  if (existing) {
    setError('اسم المستخدم غير متاح للتسجيل');
    setLoading(false);
    return;
  }

  // إرسال كود التحقق للبريد
  const { error } = await supabase.auth.signInWithOtp({
    email,
    options: {
      shouldCreateUser: true
    }
  });

  if (error) {
    setError(error.message);
    setLoading(false);
    return;
  }

  // نقل المستخدم لصفحة إدخال الكود
  router.push(`/auth/verify?email=${encodeURIComponent(email)}`);

  setLoading(false);
};

  return (
    &lt;div className="min-h-screen flex items-center justify-center p-4 bg-gradient-to-br from-purple-900/20 to-background"&gt;
      &lt;Card className="w-full max-w-md border-purple-500/20"&gt;
        &lt;CardHeader className="text-center space-y-2"&gt;
          &lt;div className="flex justify-center mb-4"&gt;
            &lt;div className="p-3 bg-gradient-purple rounded-2xl"&gt;
              &lt;Sparkles className="h-8 w-8 text-white" /&gt;
            &lt;/div&gt;
          &lt;/div&gt;
          &lt;CardTitle className="text-3xl font-bold text-gradient"&gt;استلهم&lt;/CardTitle&gt;
          &lt;CardDescription className="text-base"&gt;
            انضم إلى منصة المصممين والمبدعين
          &lt;/CardDescription&gt;
        &lt;/CardHeader&gt;
        &lt;CardContent&gt;
          &lt;form onSubmit={handleSignup} className="space-y-4"&gt;
            &lt;div className="space-y-2"&gt;
              &lt;Label htmlFor="email"&gt;البريد الإلكتروني&lt;/Label&gt;
              &lt;Input
                id="email"
                type="email"
                value={email}
                onChange={(e) =&gt; setEmail(e.target.value)}
                required
                className="text-right"
                placeholder="email@example.com"
              /&gt;
            &lt;/div&gt;

            &lt;div className="space-y-2"&gt;
              &lt;Label htmlFor="password"&gt;كلمة المرور&lt;/Label&gt;
              &lt;Input
                id="password"
                type="password"
                value={password}
                onChange={(e) =&gt; setPassword(e.target.value)}
                required
                minLength={6}
                className="text-right"
                placeholder="••••••••"
              /&gt;
            &lt;/div&gt;

            &lt;div className="space-y-2"&gt;
              &lt;Label htmlFor="username"&gt;اسم المستخدم&lt;/Label&gt;
              &lt;div className="relative"&gt;
                &lt;Input
                  id="username"
                  type="text"
                  value={username}
                  onChange={(e) =&gt; setUsername(e.target.value.toLowerCase())}
                  required
                  maxLength={25}
                  className="text-right pl-10"
                  placeholder="اسم المستخدم"
                /&gt;
                {username.length &gt;= 3 &amp;&amp; (
                  &lt;div className="absolute left-3 top-1/2 -translate-y-1/2"&gt;
                    {checkingUsername ? (
                      &lt;Loader2 className="h-4 w-4 animate-spin text-muted-foreground" /&gt;
                    ) : usernameAvailable === true ? (
                      &lt;Check className="h-4 w-4 text-green-500" /&gt;
                    ) : usernameAvailable === false ? (
                      &lt;X className="h-4 w-4 text-red-500" /&gt;
                    ) : null}
                  &lt;/div&gt;
                )}
              &lt;/div&gt;
              &lt;div className="flex items-center justify-between text-xs"&gt;
                &lt;div&gt;
                  {username.length &gt;= 3 &amp;&amp; !checkingUsername &amp;&amp; usernameAvailable === true &amp;&amp; (
                    &lt;span className="text-green-500 flex items-center gap-1"&gt;
                      &lt;Check className="h-3 w-3" /&gt;
                      اسم المستخدم متاح
                    &lt;/span&gt;
                  )}
                  {username.length &gt;= 3 &amp;&amp; !checkingUsername &amp;&amp; usernameAvailable === false &amp;&amp; (
                    &lt;span className="text-red-500 flex items-center gap-1"&gt;
                      &lt;X className="h-3 w-3" /&gt;
                      اسم المستخدم غير متاح للتسجيل
                    &lt;/span&gt;
                  )}
                &lt;/div&gt;
                &lt;span className="text-muted-foreground"&gt;
                  {username.length}/25 حرف
                &lt;/span&gt;
              &lt;/div&gt;
            &lt;/div&gt;

            &lt;div className="space-y-2"&gt;
              &lt;Label&gt;نوع الحساب&lt;/Label&gt;
              &lt;div className="grid grid-cols-1 gap-2"&gt;
                &lt;button
                  type="button"
                  onClick={() =&gt; setAccountType('designer')}
                  className={`p-4 rounded-lg border-2 transition-all text-right ${
                    accountType === 'designer'
                      ? 'border-purple-500 bg-purple-500/10'
                      : 'border-border hover:border-purple-500/50'
                  }`}
                &gt;
                  &lt;div className="font-semibold"&gt;مصمم&lt;/div&gt;
                  &lt;div className="text-sm text-muted-foreground"&gt;
                    أعرض تصاميمي وخدماتي
                  &lt;/div&gt;
                &lt;/button&gt;
                &lt;button
                  type="button"
                  onClick={() =&gt; setAccountType('seeker')}
                  className={`p-4 rounded-lg border-2 transition-all text-right ${
                    accountType === 'seeker'
                      ? 'border-purple-500 bg-purple-500/10'
                      : 'border-border hover:border-purple-500/50'
                  }`}
                &gt;
                  &lt;div className="font-semibold"&gt;باحث عن تصميم&lt;/div&gt;
                  &lt;div className="text-sm text-muted-foreground"&gt;
                    أبحث عن مصممين ومشاريع
                  &lt;/div&gt;
                &lt;/button&gt;
                &lt;button
                  type="button"
                  onClick={() =&gt; setAccountType('general')}
                  className={`p-4 rounded-lg border-2 transition-all text-right ${
                    accountType === 'general'
                      ? 'border-purple-500 bg-purple-500/10'
                      : 'border-border hover:border-purple-500/50'
                  }`}
                &gt;
                  &lt;div className="font-semibold"&gt;حساب عام&lt;/div&gt;
                  &lt;div className="text-sm text-muted-foreground"&gt;
                    للتصفح والمتابعة
                  &lt;/div&gt;
                &lt;/button&gt;
              &lt;/div&gt;
            &lt;/div&gt;

            {error &amp;&amp; (
              &lt;div className="p-3 rounded-lg bg-destructive/10 border border-destructive/20 text-destructive text-sm text-center"&gt;
                {error}
              &lt;/div&gt;
            )}

            &lt;Button
              type="submit"
              disabled={loading}
              className="w-full gradient-purple hover:opacity-90"
            &gt;
              {loading ? 'جاري الإنشاء...' : 'إنشاء حساب'}
            &lt;/Button&gt;

            &lt;p className="text-center text-sm text-muted-foreground"&gt;
              لديك حساب بالفعل؟{' '}
              &lt;Link href="/auth/login" className="text-purple-400 hover:text-purple-300"&gt;
                تسجيل الدخول
              &lt;/Link&gt;
            &lt;/p&gt;
          &lt;/form&gt;
        &lt;/CardContent&gt;
      &lt;/Card&gt;
    &lt;/div&gt;
  );
}

'use client';

import { useState } from 'react';
import { useSearchParams, useRouter } from 'next/navigation';
import { supabase } from '@/lib/supabase';
import { Button } from '@/components/ui/button';
import { Input } from '@/components/ui/input';
import { CheckCircle } from "lucide-react";

export default function VerifyPage() {

  const params = useSearchParams();
  const router = useRouter();
  const email = params.get('email') || '';

  const [code, setCode] = useState('');
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState('');
  const [success, setSuccess] = useState(false);

const handleVerify = async () =&gt; {

  setLoading(true);
  setError('');

  const { error } = await supabase.auth.verifyOtp({
    email,
    token: code,
    type: 'email'
  });

  if (error) {
    setError('الكود غير صحيح');
    setLoading(false);
    return;
  }

  // تسجيل الخروج
  await supabase.auth.signOut();

  // إظهار رسالة النجاح
  setSuccess(true);

  // الانتظار قليلاً ثم تحويل المستخدم
  setTimeout(() =&gt; {
    router.push('/auth/login');
  }, 1500);
};

return (
  &lt;div className="min-h-screen flex items-center justify-center"&gt;

    &lt;div className="w-full max-w-sm space-y-4 text-center"&gt;

      {!success &amp;&amp; (
        &lt;&gt;
          &lt;h2 className="text-xl font-bold"&gt;
            أدخل كود التحقق
          &lt;/h2&gt;

          &lt;Input
            placeholder="123456"
            value={code}
            onChange={(e)=&gt;setCode(e.target.value)}
          /&gt;

          {error &amp;&amp; (
            &lt;p className="text-red-500 text-sm"&gt;
              {error}
            &lt;/p&gt;
          )}

          &lt;Button
            onClick={handleVerify}
            disabled={loading}
            className="w-full"
          &gt;
            تأكيد
          &lt;/Button&gt;
        &lt;/&gt;
      )}

     {success &amp;&amp; (
  &lt;div className="space-y-4"&gt;

    &lt;div className="flex justify-center"&gt;
      &lt;CheckCircle className="w-16 h-16 text-green-500" /&gt;
    &lt;/div&gt;

    &lt;h2 className="text-xl font-bold"&gt;
      تم تفعيل الحساب بنجاح
    &lt;/h2&gt;

    &lt;p className="text-sm text-gray-400"&gt;
      جاري تحويلك إلى صفحة تسجيل الدخول
    &lt;/p&gt;

  &lt;/div&gt;
)}

    &lt;/div&gt;

  &lt;/div&gt;
);
}

@import url('https://fonts.googleapis.com/css2?family=Cairo:wght@400;500;600;700&amp;display=swap');

@tailwind base;
@tailwind components;
@tailwind utilities;

@layer base {
  :root {
    --background: 240 10% 3.9%;
    --foreground: 0 0% 98%;
    --card: 240 10% 7%;
    --card-foreground: 0 0% 98%;
    --popover: 240 10% 7%;
    --popover-foreground: 0 0% 98%;
    --primary: 270 91% 65%;
    --primary-foreground: 0 0% 100%;
    --secondary: 240 5% 15%;
    --secondary-foreground: 0 0% 98%;
    --muted: 240 5% 15%;
    --muted-foreground: 240 5% 64.9%;
    --accent: 270 91% 65%;
    --accent-foreground: 0 0% 100%;
    --destructive: 0 62.8% 50.6%;
    --destructive-foreground: 0 0% 98%;
    --border: 240 5% 15%;
    --input: 240 5% 15%;
    --ring: 270 91% 65%;
    --radius: 0.5rem;
  }
}

@layer base {
  * {
    @apply border-border;
  }

  body {
    @apply bg-background text-foreground;
    font-family: 'Cairo', sans-serif;
    direction: rtl;
  }

  html {
    direction: rtl;
  }
}

@layer utilities {
  .gradient-purple {
    background: linear-gradient(135deg, #a855f7 0%, #7c3aed 100%);
  }

  .text-gradient {
    background: linear-gradient(135deg, #a855f7 0%, #7c3aed 100%);
    -webkit-background-clip: text;
    -webkit-text-fill-color: transparent;
    background-clip: text;
  }

  .scrollbar-hide {
    -ms-overflow-style: none;
    scrollbar-width: none;
  }

  .scrollbar-hide::-webkit-scrollbar {
    display: none;
  }
}

