      router.push('/auth/login');
    }
  }, [user, authLoading, router]);

  if (authLoading || !user) {
    return (
      &lt;div className="min-h-screen flex items-center justify-center"&gt;
        &lt;Loader2 className="h-8 w-8 animate-spin text-blue-600" /&gt;
      &lt;/div&gt;
