      {/* 🔥 الأقسام هنا (ثابتة فوق المنشورات) */}
      &lt;CategoryTabs /&gt;

      {/* 🔥 المنشورات */}
      &lt;FeedContainer userId={user.id} /&gt;

    &lt;/main&gt;
  );
}

