'use client';

import { useState, useEffect } from 'react';
import { useAuth } from '@/lib/auth-context';
import { supabase } from '@/lib/supabase';
import { Button } from './ui/button';
import { Input } from './ui/input';
import { Search as SearchIcon, Chrome as Home, User, CirclePlus as PlusCircle, Users, Bell } from 'lucide-react';
import Link from 'next/link';
import { useRouter } from 'next/navigation';

export function Navbar() {
  const { user, profile } = useAuth();
  const router = useRouter();
  const [searchQuery, setSearchQuery] = useState('');
  const [unreadCount, setUnreadCount] = useState(0);

  useEffect(() =&gt; {
    if (user) {
      fetchUnreadCount();
      const interval = setInterval(fetchUnreadCount, 30000);
      return () =&gt; clearInterval(interval);
    }
  }, [user]);

  const fetchUnreadCount = async () =&gt; {
    if (!user) return;

    const { count } = await supabase
      .from('notifications')
      .select('*', { count: 'exact', head: true })
      .eq('user_id', user.id)
      .eq('is_read', false);

    setUnreadCount(count || 0);
  };

  if (!user) return null;

  const handleSearch = (e: React.FormEvent) =&gt; {
    e.preventDefault();
    if (searchQuery.trim()) {
      router.push(`/search?q=${encodeURIComponent(searchQuery)}`);
    }
  };

  return (
    &lt;nav className="sticky top-0 z-50 bg-card/80 backdrop-blur-lg border-b border-border"&gt;
      &lt;div className="max-w-4xl mx-auto px-6 py-3 space-y-3"&gt;
        &lt;div className="flex items-center justify-between gap-6"&gt;
          &lt;Link href="/" className="flex items-center gap-0.5 flex-shrink-0"&gt;
            &lt;span className="font-bold text-xl text-gradient leading-none"&gt;
              استلهم
            &lt;/span&gt;
          &lt;/Link&gt;

          &lt;form onSubmit={handleSearch} className="flex-1 max-w-xs hidden sm:flex"&gt;
            &lt;div className="relative w-full"&gt;
              &lt;button
                type="submit"
                className="absolute right-3 top-1/2 transform -translate-y-1/2 cursor-pointer z-10"
              &gt;
                &lt;SearchIcon className="h-4 w-4 text-muted-foreground hover:text-purple-500 transition-colors" /&gt;
              &lt;/button&gt;
              &lt;Input
                value={searchQuery}
                onChange={(e) =&gt; setSearchQuery(e.target.value)}
                placeholder="بحث..."
                className="pl-4 pr-9 text-right h-8 text-sm"
              /&gt;
            &lt;/div&gt;
          &lt;/form&gt;

          &lt;div className="flex items-center gap-2"&gt;
            &lt;Button
              onClick={() =&gt; router.push('/')}
              variant="ghost"
              size="sm"
              className="gap-2"
            &gt;
              &lt;Home className="h-4 w-4" /&gt;
              &lt;span className="hidden sm:inline text-sm"&gt;الرئيسية&lt;/span&gt;
            &lt;/Button&gt;
            &lt;Button
              onClick={() =&gt; router.push('/explore/trending')}
              variant="ghost"
              size="sm"
            &gt;
              &lt;span className="text-sm"&gt;الترند ↗&lt;/span&gt;
            &lt;/Button&gt;
            &lt;Button
              onClick={() =&gt; router.push('/explore/designers')}
              variant="ghost"
              size="sm"
              className="gap-2"
            &gt;
              &lt;Users className="h-4 w-4" /&gt;
              &lt;span className="hidden sm:inline text-sm"&gt;مصممون&lt;/span&gt;
            &lt;/Button&gt;
            &lt;Button
              onClick={() =&gt; router.push('/notifications')}
              variant="ghost"
              size="sm"
              className="gap-2 relative"
            &gt;
              &lt;Bell className="h-4 w-4" /&gt;
              {unreadCount &gt; 0 &amp;&amp; (
                &lt;span className="absolute -top-1 -right-1 h-4 w-4 rounded-full bg-red-500 text-white text-xs flex items-center justify-center"&gt;
                  {unreadCount &gt; 9 ? '9+' : unreadCount}
                &lt;/span&gt;
              )}
              &lt;span className="hidden sm:inline text-sm"&gt;الإشعارات&lt;/span&gt;
            &lt;/Button&gt;
            &lt;Button
              onClick={() =&gt; router.push(`/profile/${profile?.username}`)}
              variant="ghost"
              size="sm"
              className="gap-2"
            &gt;
              &lt;User className="h-4 w-4" /&gt;
              &lt;span className="hidden sm:inline text-sm"&gt;ملفي&lt;/span&gt;
            &lt;/Button&gt;
            &lt;Button
              onClick={() =&gt; router.push('/post/create')}
              size="sm"
              className="gradient-purple gap-2"
            &gt;
              &lt;PlusCircle className="h-4 w-4" /&gt;
              &lt;span className="hidden sm:inline text-sm"&gt;إنشاء منشور&lt;/span&gt;
            &lt;/Button&gt;
          &lt;/div&gt;
        &lt;/div&gt;

        &lt;form onSubmit={handleSearch} className="flex sm:hidden"&gt;
          &lt;div className="relative w-full"&gt;
            &lt;button
              type="submit"
              className="absolute right-3 top-1/2 transform -translate-y-1/2 cursor-pointer z-10"
            &gt;
              &lt;SearchIcon className="h-4 w-4 text-muted-foreground hover:text-purple-500 transition-colors" /&gt;
            &lt;/button&gt;
            &lt;Input
              value={searchQuery}
              onChange={(e) =&gt; setSearchQuery(e.target.value)}
              placeholder="ابحث..."
              className="pl-4 pr-9 text-right h-8 text-sm w-full"
            /&gt;
          &lt;/div&gt;
        &lt;/form&gt;
      &lt;/div&gt;

      &lt;div className="border-t border-border/50 bg-card/60"&gt;
        &lt;div className="max-w-4xl mx-auto px-6 py-2"&gt;
          &lt;p className="text-xs text-muted-foreground/70 text-center"&gt;
            استكشف التصاميم والإبداعات من المصممين حول العالم
          &lt;/p&gt;
        &lt;/div&gt;
      &lt;/div&gt;
    &lt;/nav&gt;
  );
}

'use client';

import { Ad } from '@/types/ad';
import { Card } from '@/components/ui/card';
import { Badge } from '@/components/ui/badge';
import { ExternalLink } from 'lucide-react';

interface AdCardProps {
  ad: Ad;
  onAdClick?: (adId: string) =&gt; void;
}

export function AdCard({ ad, onAdClick }: AdCardProps) {
  const handleClick = () =&gt; {
    onAdClick?.(ad.id);
    if (ad.link_url) {
      window.open(ad.link_url, '_blank');
    }
  };

  return (
    &lt;Card
      className="p-6 bg-gradient-to-br from-blue-50 to-indigo-50 border-blue-200 cursor-pointer hover:shadow-md transition-shadow"
      onClick={handleClick}
    &gt;
      &lt;div className="flex items-start gap-3"&gt;
        &lt;Badge variant="secondary" className="bg-blue-600 text-white"&gt;
          إعلان
        &lt;/Badge&gt;
        {ad.is_pinned &amp;&amp; (
          &lt;Badge variant="secondary" className="bg-yellow-500 text-white"&gt;
            مثبت
          &lt;/Badge&gt;
        )}
      &lt;/div&gt;

      &lt;div className="mt-4"&gt;
        &lt;h3 className="text-lg font-bold text-gray-900 mb-2"&gt;{ad.title}&lt;/h3&gt;
        &lt;p className="text-gray-700 mb-4"&gt;{ad.description}&lt;/p&gt;

        {ad.image_url &amp;&amp; (
          &lt;img
            src={ad.image_url}
            alt={ad.title}
            className="w-full h-48 object-cover rounded-lg mb-4"
          /&gt;
        )}

        {ad.link_url &amp;&amp; (
          &lt;div className="flex items-center gap-2 text-blue-600 font-medium"&gt;
            &lt;span&gt;اعرف المزيد&lt;/span&gt;
            &lt;ExternalLink className="w-4 h-4" /&gt;
          &lt;/div&gt;
        )}
      &lt;/div&gt;
    &lt;/Card&gt;
  );
}

'use client';

import { FeedItem as FeedItemType } from '@/types/feed';
import { PostCard } from './post-card';
import { AdCard } from './ad-card';

interface FeedItemProps {
  item: FeedItemType;
  onLike?: (postId: string) =&gt; void;
  onComment?: (postId: string) =&gt; void;
  onAdClick?: (adId: string) =&gt; void;
}

export function FeedItem({ item, onLike, onComment, onAdClick }: FeedItemProps) {
  if (item.type === 'post') {
    return &lt;PostCard post={item.data} onLike={onLike} onComment={onComment} /&gt;;
  }

  if (item.type === 'ad') {
    return &lt;AdCard ad={item.data} onAdClick={onAdClick} /&gt;;
  }

  return null;
}

'use client';

import { PostWithUser } from '@/types/post';
import { Avatar, AvatarFallback, AvatarImage } from '@/components/ui/avatar';
import { Badge } from '@/components/ui/badge';
import { Heart, MessageCircle, Share2 } from 'lucide-react';
import { formatDistanceToNow } from 'date-fns';
import { ar } from 'date-fns/locale';
import { cn } from '@/lib/utils';

interface PostCardProps {
  post: PostWithUser;
  onLike?: (postId: string) =&gt; void;
  onComment?: (postId: string) =&gt; void;
}

const postTypeLabels: Record&lt;string, string&gt; = {
  general: 'منشور عام',
  design: 'تصميم',
  request: 'طلب',
  offer: 'عرض',
  attachment: 'ملحق',
};

const postTypeBadgeColors: Record&lt;string, string&gt; = {
  general: 'bg-blue-500/10 text-blue-600 border-blue-500/20',
  design: 'bg-purple-500/10 text-purple-600 border-purple-500/20',
  request: 'bg-orange-500/10 text-orange-600 border-orange-500/20',
  offer: 'bg-green-500/10 text-green-600 border-green-500/20',
  attachment: 'bg-pink-500/10 text-pink-600 border-pink-500/20',
};

export function PostCard({ post, onLike, onComment }: PostCardProps) {
  const timeAgo = formatDistanceToNow(new Date(post.created_at), {
    addSuffix: true,
    locale: ar,
  });

  return (
    &lt;article className="border-b border-border/40 bg-background p-4 hover:bg-muted/20 transition-colors"&gt;
      &lt;div className="flex gap-3"&gt;
        &lt;Avatar className="h-12 w-12 border-2 border-border/40"&gt;
          &lt;AvatarImage src={post.user?.avatar_url || undefined} /&gt;
          &lt;AvatarFallback className="bg-gradient-to-br from-purple-500 to-blue-500 text-white"&gt;
            {post.user?.username?.[0]?.toUpperCase() || 'U'}
          &lt;/AvatarFallback&gt;
        &lt;/Avatar&gt;

        &lt;div className="flex-1 min-w-0"&gt;
          &lt;div className="flex items-start justify-between gap-2 mb-1"&gt;
            &lt;div className="flex items-center gap-2 flex-wrap"&gt;
              &lt;span className="font-semibold text-foreground"&gt;
                {post.user?.display_name || post.user?.username || 'مستخدم'}
              &lt;/span&gt;
              &lt;span className="text-sm text-muted-foreground"&gt;
                @{post.user?.username || 'user'}
              &lt;/span&gt;
              &lt;span className="text-sm text-muted-foreground"&gt;·&lt;/span&gt;
              &lt;span className="text-sm text-muted-foreground"&gt;{timeAgo}&lt;/span&gt;
            &lt;/div&gt;

            &lt;Badge
              variant="outline"
              className={cn(
                'text-xs font-medium border',
                postTypeBadgeColors[post.type] || postTypeBadgeColors.general
              )}
            &gt;
              {postTypeLabels[post.type] || 'منشور'}
            &lt;/Badge&gt;
          &lt;/div&gt;

          {post.title &amp;&amp; (
            &lt;h3 className="font-semibold text-lg mb-2"&gt;{post.title}&lt;/h3&gt;
          )}

          &lt;p className="text-foreground whitespace-pre-wrap mb-3"&gt;
            {post.description}
          &lt;/p&gt;

          {post.images &amp;&amp; post.images.length &gt; 0 &amp;&amp; (
            &lt;div className={cn(
              "grid gap-2 mb-3 rounded-lg overflow-hidden",
              post.images.length === 1 &amp;&amp; "grid-cols-1",
              post.images.length === 2 &amp;&amp; "grid-cols-2",
              post.images.length &gt;= 3 &amp;&amp; "grid-cols-2"
            )}&gt;
              {post.images.slice(0, 4).map((image, idx) =&gt; (
                &lt;div
                  key={idx}
                  className={cn(
                    "relative bg-muted overflow-hidden rounded-lg",
                    post.images.length === 1 &amp;&amp; "aspect-video",
                    post.images.length &gt;= 2 &amp;&amp; "aspect-square",
                    post.images.length === 3 &amp;&amp; idx === 0 &amp;&amp; "col-span-2"
                  )}
                &gt;
                  &lt;img
                    src={image}
                    alt=""
                    className="w-full h-full object-cover"
                  /&gt;
                &lt;/div&gt;
              ))}
            &lt;/div&gt;
          )}

          {post.price &amp;&amp; (
            &lt;div className="mb-3 inline-block px-3 py-1.5 bg-green-500/10 text-green-600 rounded-lg text-sm font-semibold"&gt;
              {post.price} ر.س
            &lt;/div&gt;
          )}

          &lt;div className="flex items-center gap-6 text-muted-foreground"&gt;
            &lt;button
              onClick={() =&gt; onLike?.(post.id)}
              className={cn(
                "flex items-center gap-2 hover:text-pink-600 transition-colors group",
                post.is_liked &amp;&amp; "text-pink-600"
              )}
            &gt;
              &lt;Heart
                className={cn(
                  "h-5 w-5 group-hover:scale-110 transition-transform",
                  post.is_liked &amp;&amp; "fill-current"
                )}
              /&gt;
              &lt;span className="text-sm font-medium"&gt;{post.likes_count || 0}&lt;/span&gt;
            &lt;/button&gt;

            &lt;button
              onClick={() =&gt; onComment?.(post.id)}
              className="flex items-center gap-2 hover:text-blue-600 transition-colors group"
            &gt;
              &lt;MessageCircle className="h-5 w-5 group-hover:scale-110 transition-transform" /&gt;
              &lt;span className="text-sm font-medium"&gt;{post.comments_count || 0}&lt;/span&gt;
            &lt;/button&gt;

            &lt;button className="flex items-center gap-2 hover:text-green-600 transition-colors group"&gt;
              &lt;Share2 className="h-5 w-5 group-hover:scale-110 transition-transform" /&gt;
            &lt;/button&gt;

            {post.views_count !== undefined &amp;&amp; (
              &lt;span className="text-sm mr-auto"&gt;
                {post.views_count} مشاهدة
              &lt;/span&gt;
            )}
          &lt;/div&gt;
        &lt;/div&gt;
      &lt;/div&gt;
    &lt;/article&gt;
  );
}

'use client';

import * as React from 'react';
import * as AccordionPrimitive from '@radix-ui/react-accordion';
import { ChevronDown } from 'lucide-react';

import { cn } from '@/lib/utils';

const Accordion = AccordionPrimitive.Root;

