    &lt;span className="sr-only"&gt;More pages&lt;/span&gt;
  &lt;/span&gt;
);
PaginationEllipsis.displayName = 'PaginationEllipsis';

export {
  Pagination,
  PaginationContent,
  PaginationEllipsis,
  PaginationItem,
  PaginationLink,
  PaginationNext,
  PaginationPrevious,
