'use client';

import { useState, useEffect } from 'react';
import { FeedTab } from '@/types/feed';
import { FeedItem as FeedItemType } from '@/types/feed';
import { getFeed } from '@/services/feed.service';
import { likePost, unlikePost } from '@/services/post.service';
import { trackAdClick } from '@/services/ads.service';
import { MainHeader } from '@/components/layout/main-header';
import { RightSidebar } from '@/components/layout/right-sidebar';
import { CategoryTabs } from '@/components/layout/category-tabs';
import { FeedItem } from '@/components/shared/feed-item';
import { Loader as Loader2 } from 'lucide-react';

interface FeedContainerProps {
  userId: string;
}

export function FeedContainer({ userId }: FeedContainerProps) {
  const [activeTab, setActiveTab] = useState&lt;FeedTab&gt;('custom');
  const [feedItems, setFeedItems] = useState&lt;FeedItemType[]&gt;([]);
  const [isLoading, setIsLoading] = useState(true);
  const [page, setPage] = useState(1);
  const [hasMore, setHasMore] = useState(false);

  useEffect(() =&gt; {
    loadFeed();
  }, [activeTab]);

  useEffect(() =&gt; {
    const handleScroll = () =&gt; {
      if (
        window.innerHeight + window.scrollY &gt;= document.documentElement.scrollHeight - 500 &amp;&amp;
        hasMore &amp;&amp;
        !isLoading
      ) {
        loadMore();
      }
    };

    window.addEventListener('scroll', handleScroll);
    return () =&gt; window.removeEventListener('scroll', handleScroll);
  }, [hasMore, isLoading, page]);

  async function loadFeed() {
    setIsLoading(true);
    try {
      const response = await getFeed({
        tab: activeTab,
        userId,
        page: 1,
        limit: 20,
      });
      setFeedItems(response.items);
      setHasMore(response.meta.hasMore);
      setPage(1);
    } catch (error) {
      console.error('Failed to load feed:', error);
    } finally {
      setIsLoading(false);
    }
  }

  async function loadMore() {
    if (!hasMore || isLoading) return;

    setIsLoading(true);
    try {
      const response = await getFeed({
        tab: activeTab,
        userId,
        page: page + 1,
        limit: 20,
      });
      setFeedItems([...feedItems, ...response.items]);
      setHasMore(response.meta.hasMore);
      setPage(page + 1);
    } catch (error) {
      console.error('Failed to load more:', error);
    } finally {
      setIsLoading(false);
    }
  }

  async function handleLike(postId: string) {
    const item = feedItems.find(i =&gt; i.id === postId);
    if (!item || item.type !== 'post') return;

    const isLiked = item.data.is_liked;

    setFeedItems(
      feedItems.map(i =&gt;
        i.id === postId &amp;&amp; i.type === 'post'
          ? {
              ...i,
              data: {
                ...i.data,
                is_liked: !isLiked,
                likes_count: i.data.likes_count + (isLiked ? -1 : 1),
              },
            }
          : i
      )
    );

    try {
      if (isLiked) {
        await unlikePost(postId, userId);
      } else {
        await likePost(postId, userId);
      }
    } catch (error) {
      console.error('Failed to toggle like:', error);
      setFeedItems(
        feedItems.map(i =&gt;
          i.id === postId &amp;&amp; i.type === 'post'
            ? {
                ...i,
                data: {
                  ...i.data,
                  is_liked: isLiked,
                  likes_count: i.data.likes_count + (isLiked ? 1 : -1),
                },
              }
            : i
        )
      );
    }
  }

  async function handleComment(postId: string) {
    console.log('Open comment modal for post:', postId);
  }

  async function handleAdClick(adId: string) {
    try {
      await trackAdClick(adId, userId);
    } catch (error) {
      console.error('Failed to track ad click:', error);
    }
  }

  function handleTabChange(tab: FeedTab) {
    setActiveTab(tab);
  }

  return (
    &lt;div className="min-h-screen bg-background"&gt;
      &lt;MainHeader /&gt;

      &lt;div className="pt-16 flex"&gt;
        &lt;RightSidebar /&gt;

        &lt;main className="flex-1 mr-80"&gt;
          &lt;CategoryTabs activeTab={activeTab} onTabChange={handleTabChange} /&gt;

          &lt;div className="max-w-2xl mx-auto"&gt;
            {isLoading &amp;&amp; feedItems.length === 0 ? (
              &lt;div className="flex items-center justify-center py-12"&gt;
                &lt;Loader2 className="h-8 w-8 animate-spin text-purple-600" /&gt;
              &lt;/div&gt;
            ) : feedItems.length === 0 ? (
              &lt;div className="text-center py-12 px-4"&gt;
                &lt;p className="text-muted-foreground"&gt;لا توجد منشورات&lt;/p&gt;
              &lt;/div&gt;
            ) : (
              &lt;&gt;
                {feedItems.map((item) =&gt; (
                  &lt;FeedItem
                    key={item.id}
                    item={item}
                    onLike={handleLike}
                    onComment={handleComment}
                    onAdClick={handleAdClick}
                  /&gt;
                ))}

                {isLoading &amp;&amp; (
                  &lt;div className="flex items-center justify-center py-8 border-b border-border/40"&gt;
                    &lt;Loader2 className="h-6 w-6 animate-spin text-purple-600" /&gt;
                  &lt;/div&gt;
                )}
              &lt;/&gt;
            )}
          &lt;/div&gt;
        &lt;/main&gt;
      &lt;/div&gt;
    &lt;/div&gt;
  );
}

'use client';

// Inspired by react-hot-toast library
import * as React from 'react';

import type { ToastActionElement, ToastProps } from '@/components/ui/toast';

const TOAST_LIMIT = 1;
const TOAST_REMOVE_DELAY = 1000000;

type ToasterToast = ToastProps &amp; {
  id: string;
  title?: React.ReactNode;
  description?: React.ReactNode;
  action?: ToastActionElement;
};

const actionTypes = {
  ADD_TOAST: 'ADD_TOAST',
  UPDATE_TOAST: 'UPDATE_TOAST',
  DISMISS_TOAST: 'DISMISS_TOAST',
  REMOVE_TOAST: 'REMOVE_TOAST',
} as const;

let count = 0;

function genId() {
  count = (count + 1) % Number.MAX_SAFE_INTEGER;
  return count.toString();
}

type ActionType = typeof actionTypes;

type Action =
  | {
      type: ActionType['ADD_TOAST'];
      toast: ToasterToast;
    }
  | {
      type: ActionType['UPDATE_TOAST'];
      toast: Partial&lt;ToasterToast&gt;;
    }
  | {
      type: ActionType['DISMISS_TOAST'];
      toastId?: ToasterToast['id'];
    }
  | {
      type: ActionType['REMOVE_TOAST'];
      toastId?: ToasterToast['id'];
    };

interface State {
  toasts: ToasterToast[];
}

const toastTimeouts = new Map&lt;string, ReturnType&lt;typeof setTimeout&gt;&gt;();

const addToRemoveQueue = (toastId: string) =&gt; {
  if (toastTimeouts.has(toastId)) {
    return;
  }

  const timeout = setTimeout(() =&gt; {
    toastTimeouts.delete(toastId);
    dispatch({
      type: 'REMOVE_TOAST',
      toastId: toastId,
    });
  }, TOAST_REMOVE_DELAY);

  toastTimeouts.set(toastId, timeout);
};

export const reducer = (state: State, action: Action): State =&gt; {
  switch (action.type) {
    case 'ADD_TOAST':
      return {
        ...state,
        toasts: [action.toast, ...state.toasts].slice(0, TOAST_LIMIT),
      };

    case 'UPDATE_TOAST':
      return {
        ...state,
        toasts: state.toasts.map((t) =&gt;
          t.id === action.toast.id ? { ...t, ...action.toast } : t
        ),
      };

    case 'DISMISS_TOAST': {
      const { toastId } = action;

      // ! Side effects ! - This could be extracted into a dismissToast() action,
      // but I'll keep it here for simplicity
      if (toastId) {
        addToRemoveQueue(toastId);
      } else {
        state.toasts.forEach((toast) =&gt; {
          addToRemoveQueue(toast.id);
        });
      }

      return {
        ...state,
        toasts: state.toasts.map((t) =&gt;
          t.id === toastId || toastId === undefined
            ? {
                ...t,
                open: false,
              }
            : t
        ),
      };
    }
    case 'REMOVE_TOAST':
      if (action.toastId === undefined) {
        return {
          ...state,
          toasts: [],
        };
      }
      return {
        ...state,
        toasts: state.toasts.filter((t) =&gt; t.id !== action.toastId),
      };
  }
};

const listeners: Array&lt;(state: State) =&gt; void&gt; = [];

let memoryState: State = { toasts: [] };

function dispatch(action: Action) {
  memoryState = reducer(memoryState, action);
  listeners.forEach((listener) =&gt; {
    listener(memoryState);
  });
}

type Toast = Omit&lt;ToasterToast, 'id'&gt;;

function toast({ ...props }: Toast) {
  const id = genId();

  const update = (props: ToasterToast) =&gt;
    dispatch({
      type: 'UPDATE_TOAST',
      toast: { ...props, id },
    });
  const dismiss = () =&gt; dispatch({ type: 'DISMISS_TOAST', toastId: id });

  dispatch({
    type: 'ADD_TOAST',
    toast: {
      ...props,
      id,
      open: true,
      onOpenChange: (open) =&gt; {
        if (!open) dismiss();
      },
    },
  });

  return {
    id: id,
    dismiss,
    update,
  };
}

function useToast() {
  const [state, setState] = React.useState&lt;State&gt;(memoryState);

  React.useEffect(() =&gt; {
    listeners.push(setState);
    return () =&gt; {
      const index = listeners.indexOf(setState);
      if (index &gt; -1) {
        listeners.splice(index, 1);
      }
    };
  }, [state]);

  return {
    ...state,
    toast,
    dismiss: (toastId?: string) =&gt; dispatch({ type: 'DISMISS_TOAST', toastId }),
  };
}

export { useToast, toast };

import { supabase } from './supabase';

export type AdminLevel = 'assistant' | 'deputy' | 'director';

export interface AdminUser {
  id: string;
  level: AdminLevel;
  promoted_by: string | null;
  promoted_at: string;
}

export async function checkAdminAccess(userId: string): Promise&lt;{ isAdmin: boolean; level?: AdminLevel }&gt; {
  const { data } = await supabase
    .from('admin_hierarchy')
    .select('level')
    .eq('user_id', userId)
    .maybeSingle();

  return {
    isAdmin: !!data,
    level: data?.level as AdminLevel | undefined,
  };
}

export async function logAdminAction(
  adminId: string,
  action: string,
  targetType?: string,
  targetId?: string,
  details?: Record&lt;string, any&gt;
) {
  await supabase.from('admin_activity_log').insert({
    admin_id: adminId,
    action,
    target_type: targetType,
    target_id: targetId,
    details: details || {},
  });
}

export function canManageStaff(level?: AdminLevel): boolean {
  return level === 'director';
}

export function canManageAds(level?: AdminLevel): boolean {
  return level === 'director' || level === 'deputy';
}

export function canViewActivityLog(level?: AdminLevel): boolean {
  return level === 'director';
}

'use client';

import { createContext, useContext, useEffect, useState } from 'react';
import { User } from '@supabase/supabase-js';
import { supabase } from './supabase';
import { UserProfile } from '@/types/user';
import { useRouter } from 'next/navigation';

type AuthContextType = {
  user: User | null;
  profile: UserProfile | null;
  loading: boolean;
  signOut: () =&gt; Promise&lt;void&gt;;
  refreshProfile: () =&gt; Promise&lt;void&gt;;
};

const AuthContext = createContext&lt;AuthContextType&gt;({
  user: null,
  profile: null,
  loading: true,
  signOut: async () =&gt; {},
  refreshProfile: async () =&gt; {},
});

export const useAuth = () =&gt; useContext(AuthContext);

export function AuthProvider({ children }: { children: React.ReactNode }) {
  const [user, setUser] = useState&lt;User | null&gt;(null);
  const [profile, setProfile] = useState&lt;UserProfile | null&gt;(null);
  const [loading, setLoading] = useState(true);
  const router = useRouter();

  const fetchProfile = async (userId: string) =&gt; {
    const { data, error } = await supabase
      .from('users_profile')
      .select('*')
      .eq('id', userId)
      .maybeSingle();

    if (data) {
      setProfile(data);
    }
  };

  const refreshProfile = async () =&gt; {
    if (user) {
      await fetchProfile(user.id);
    }
  };

  useEffect(() =&gt; {
    supabase.auth.getSession().then(({ data: { session } }) =&gt; {
      setUser(session?.user ?? null);
      if (session?.user) {
        fetchProfile(session.user.id);
      }
      setLoading(false);
    });

    const { data: { subscription } } = supabase.auth.onAuthStateChange(
      (_event, session) =&gt; {
        setUser(session?.user ?? null);
        if (session?.user) {
          fetchProfile(session.user.id);
        } else {
          setProfile(null);
        }
      }
    );

    return () =&gt; subscription.unsubscribe();
  }, []);

  const signOut = async () =&gt; {
    await supabase.auth.signOut();
    setUser(null);
    setProfile(null);
    router.push('/auth/login');
  };

  return (
    &lt;AuthContext.Provider value={{ user, profile, loading, signOut, refreshProfile }}&gt;
      {children}
    &lt;/AuthContext.Provider&gt;
  );
}

export function encodeId(num: number) {
  return num.toString(36)
}

export function decodeId(str: string) {
  return parseInt(str, 36)
}

import { Twitter, Instagram, Github, Globe } from "lucide-react";

export const socialPlatforms = {
  twitter: {
    label: "تويتر",
    icon: Twitter,
  },

  instagram: {
    label: "إنستغرام",
    icon: Instagram,
  },

  github: {
    label: "GitHub",
    icon: Github,
  },

  behance: {
    label: "بيهانس",
    icon: Globe,
  },

  dribbble: {
    label: "دريبل",
    icon: Globe,
  }
};

import { createClient } from '@supabase/supabase-js';

const supabaseUrl = process.env.NEXT_PUBLIC_SUPABASE_URL!;
const supabaseAnonKey = process.env.NEXT_PUBLIC_SUPABASE_ANON_KEY!;

if (!supabaseUrl || !supabaseAnonKey) {
  throw new Error('Missing Supabase environment variables');
}

export const supabase = createClient(supabaseUrl, supabaseAnonKey, {
  auth: {
    persistSession: true,
    autoRefreshToken: true,
  },
});

export function getSupabaseClient() {
  return supabase;
}

import { clsx, type ClassValue } from 'clsx';
import { twMerge } from 'tailwind-merge';

export function cn(...inputs: ClassValue[]) {
  return twMerge(clsx(inputs));
}

