import { getSupabaseClient } from '@/lib/supabase';
import { Ad, CreateAdInput } from '@/types/ad';

const supabase = getSupabaseClient();

export async function getActiveAds(): Promise&lt;Ad[]&gt; {
  const { data, error } = await supabase
    .from('ads')
    .select('*')
    .eq('is_active', true)
    .or(`end_date.is.null,end_date.gt.${new Date().toISOString()}`)
    .lte('start_date', new Date().toISOString())
    .order('is_pinned', { ascending: false })
    .order('created_at', { ascending: false });

  if (error) throw error;
  return data || [];
}

export async function getAdsForFeed(limit: number = 2): Promise&lt;Ad[]&gt; {
  const ads = await getActiveAds();

  const eligibleAds = ads.filter(ad =&gt; {
    if (ad.impressions_limit &gt; 0 &amp;&amp; ad.impressions_count &gt;= ad.impressions_limit) {
      return false;
    }
    return true;
  });

  const pinnedAds = eligibleAds.filter(ad =&gt; ad.is_pinned);
  const regularAds = eligibleAds.filter(ad =&gt; !ad.is_pinned);

  const selectedAds = [
    ...pinnedAds.slice(0, limit),
    ...regularAds.slice(0, Math.max(0, limit - pinnedAds.length))
  ];

  return selectedAds;
}

export async function trackAdImpression(adId: string): Promise&lt;void&gt; {
  const { error } = await supabase.rpc('increment_ad_impressions', {
    ad_uuid: adId
  });

  if (error) throw error;
}

export async function trackAdClick(adId: string, userId: string | null): Promise&lt;void&gt; {
  await supabase.rpc('increment_ad_clicks', {
    ad_uuid: adId
  });

  const { error } = await supabase
    .from('ad_clicks')
    .insert({
      ad_id: adId,
      user_id: userId,
    });

  if (error) throw error;
}

export async function createAd(input: CreateAdInput): Promise&lt;Ad&gt; {
  const { data, error } = await supabase
    .from('ads')
    .insert({
      title: input.title,
      description: input.description,
      image_url: input.image_url || null,
      link_url: input.link_url || null,
      is_pinned: input.is_pinned || false,
      impressions_limit: input.impressions_limit || 0,
      start_date: input.start_date || new Date().toISOString(),
      end_date: input.end_date || null,
    })
    .select()
    .single();

  if (error) throw error;
  return data;
}

import { getSupabaseClient } from '@/lib/supabase';
import { FeedParams, FeedResponse, FeedItem } from '@/types/feed';
import { PostWithUser } from '@/types/post';
import { getAdsForFeed, trackAdImpression } from './ads.service';
import { getUserPreferences, getFollowing } from './user.service';

const supabase = getSupabaseClient();

const AD_INJECTION_INTERVAL = 5;

export async function getFeed(params: FeedParams): Promise&lt;FeedResponse&gt; {
  const {
    tab,
    userId,
    page = 1,
    limit = 20,
  } = params;

  let postsQuery = supabase
    .from('posts')
    .select(`
      *,
      user:users_profile!posts_user_id_fkey(
        id,
        username,
        display_name,
        avatar_url
      )
    `, { count: 'exact' });

  switch (tab) {
    case 'custom':
      const preferences = await getUserPreferences(userId);
      const feedTypes = preferences?.custom_feed_types || ['general', 'design', 'request', 'offer', 'attachment'];
      postsQuery = postsQuery.in('type', feedTypes);
      break;

    case 'general':
      postsQuery = postsQuery.eq('type', 'general');
      break;

    case 'design':
      postsQuery = postsQuery.eq('type', 'design');
      break;

    case 'request':
      postsQuery = postsQuery.eq('type', 'request');
      break;

    case 'offer':
      postsQuery = postsQuery.eq('type', 'offer');
      break;

    case 'following':
      const followingIds = await getFollowing(userId);
      if (followingIds.length === 0) {
        return {
          items: [],
          meta: {
            page,
            limit,
            hasMore: false,
            total: 0,
          },
        };
      }
      postsQuery = postsQuery.in('user_id', followingIds);
      break;
  }

  const offset = (page - 1) * limit;
  postsQuery = postsQuery
    .order('created_at', { ascending: false })
    .range(offset, offset + limit - 1);

  const { data: posts, error, count } = await postsQuery;

  if (error) throw error;

  const postsWithLikes = await enrichPostsWithLikes(posts || [], userId);

  const ads = await getAdsForFeed(2);

  const feedItems: FeedItem[] = [];
  let adIndex = 0;

  postsWithLikes.forEach((post, index) =&gt; {
    feedItems.push({
      id: post.id,
      type: 'post',
      data: post,
    });

    if ((index + 1) % AD_INJECTION_INTERVAL === 0 &amp;&amp; adIndex &lt; ads.length) {
      const ad = ads[adIndex];
      feedItems.push({
        id: ad.id,
        type: 'ad',
        data: ad,
      });

      trackAdImpression(ad.id).catch(console.error);
      adIndex++;
    }
  });

  return {
    items: feedItems,
    meta: {
      page,
      limit,
      hasMore: (count || 0) &gt; offset + limit,
      total: count || 0,
    },
  };
}

async function enrichPostsWithLikes(
  posts: PostWithUser[],
  userId: string
): Promise&lt;PostWithUser[]&gt; {
  if (posts.length === 0) return [];

  const postIds = posts.map(p =&gt; p.id);

  const { data: likes, error } = await supabase
    .from('likes')
    .select('post_id')
    .eq('user_id', userId)
    .in('post_id', postIds);

  if (error) throw error;

  const likedPostIds = new Set(likes?.map(l =&gt; l.post_id) || []);

  return posts.map(post =&gt; ({
    ...post,
    is_liked: likedPostIds.has(post.id),
  }));
}

import { getSupabaseClient } from '@/lib/supabase';
import { Post, PostWithUser, CreatePostInput, UpdatePostInput } from '@/types/post';

const supabase = getSupabaseClient();

export async function createPost(userId: string, input: CreatePostInput): Promise&lt;Post&gt; {
  const { data, error } = await supabase
    .from('posts')
    .insert({
      user_id: userId,
      type: input.type,
      status: input.status || 'open',
      title: input.title || null,
      description: input.description,
      images: input.images || [],
      attachments: input.attachments || [],
      price: input.price || null,
    })
    .select()
    .single();

  if (error) throw error;
  return data;
}

export async function updatePost(
  postId: string,
  userId: string,
  input: UpdatePostInput
): Promise&lt;Post&gt; {
  const { data, error } = await supabase
    .from('posts')
    .update({
      ...input,
      updated_at: new Date().toISOString(),
    })
    .eq('id', postId)
    .eq('user_id', userId)
    .select()
    .single();

  if (error) throw error;
  return data;
}

export async function deletePost(postId: string, userId: string): Promise&lt;void&gt; {
  const { error } = await supabase
    .from('posts')
    .delete()
    .eq('id', postId)
    .eq('user_id', userId);

  if (error) throw error;
}

export async function getPostById(postId: string, currentUserId?: string): Promise&lt;PostWithUser | null&gt; {
  let query = supabase
    .from('posts')
    .select(`
      *,
      user:users_profile!posts_user_id_fkey(
        id,
        username,
        display_name,
        avatar_url
      )
    `)
    .eq('id', postId)
    .maybeSingle();

  const { data: post, error } = await query;

  if (error) throw error;
  if (!post) return null;

  let isLiked = false;
  if (currentUserId) {
    const { data: likeData } = await supabase
      .from('likes')
      .select('*')
      .eq('post_id', postId)
      .eq('user_id', currentUserId)
      .maybeSingle();
    isLiked = !!likeData;
  }

  return {
    ...post,
    is_liked: isLiked,
  };
}

export async function likePost(postId: string, userId: string): Promise&lt;void&gt; {
  const { error } = await supabase
    .from('likes')
    .insert({
      post_id: postId,
      user_id: userId,
    });

  if (error) throw error;
}

export async function unlikePost(postId: string, userId: string): Promise&lt;void&gt; {
  const { error } = await supabase
    .from('likes')
    .delete()
    .eq('post_id', postId)
    .eq('user_id', userId);

  if (error) throw error;
}

export async function incrementPostViews(postId: string): Promise&lt;void&gt; {
  const { data: post } = await supabase
    .from('posts')
    .select('views_count')
    .eq('id', postId)
    .maybeSingle();

  if (post) {
    const { error } = await supabase
      .from('posts')
      .update({ views_count: post.views_count + 1 })
      .eq('id', postId);

    if (error) throw error;
  }
}

export async function getPostComments(postId: string) {
  const { data, error } = await supabase
    .from('comments')
    .select(`
      *,
      user:users_profile!comments_user_id_fkey(
        id,
        username,
        display_name,
        avatar_url
      )
    `)
    .eq('post_id', postId)
    .order('created_at', { ascending: true });

  if (error) throw error;
  return data;
}

export async function createComment(
  postId: string,
  userId: string,
  content: string
): Promise&lt;void&gt; {
  const { error } = await supabase
    .from('comments')
    .insert({
      post_id: postId,
      user_id: userId,
      content,
    });

  if (error) throw error;
}

export async function deleteComment(commentId: string, userId: string): Promise&lt;void&gt; {
  const { error } = await supabase
    .from('comments')
    .delete()
    .eq('id', commentId)
    .eq('user_id', userId);

  if (error) throw error;
}

import { getSupabaseClient } from '@/lib/supabase';
import { UserProfile, UpdateUserProfileInput, UserPreferences } from '@/types/user';

const supabase = getSupabaseClient();

export async function getCurrentUser(): Promise&lt;UserProfile | null&gt; {
  const { data: { user } } = await supabase.auth.getUser();
  if (!user) return null;

  const { data, error } = await supabase
    .from('users_profile')
    .select('*')
    .eq('id', user.id)
    .maybeSingle();

  if (error) throw error;
  return data;
}

export async function getUserById(userId: string): Promise&lt;UserProfile | null&gt; {
  const { data, error } = await supabase
    .from('users_profile')
    .select('*')
    .eq('id', userId)
    .maybeSingle();

  if (error) throw error;
  return data;
}

export async function getUserByUsername(username: string): Promise&lt;UserProfile | null&gt; {
  const { data, error } = await supabase
    .from('users_profile')
    .select('*')
    .eq('username', username)
    .maybeSingle();

  if (error) throw error;
  return data;
}

export async function createUserProfile(userId: string, username: string): Promise&lt;UserProfile&gt; {
  const { data, error } = await supabase
    .from('users_profile')
    .insert({
      id: userId,
      username,
    })
    .select()
    .single();

  if (error) throw error;
  return data;
}

export async function updateUserProfile(
  userId: string,
  input: UpdateUserProfileInput
): Promise&lt;UserProfile&gt; {
  const { data, error } = await supabase
    .from('users_profile')
    .update({
      ...input,
      updated_at: new Date().toISOString(),
    })
    .eq('id', userId)
    .select()
    .single();

  if (error) throw error;
  return data;
}

export async function getUserPreferences(userId: string): Promise&lt;UserPreferences | null&gt; {
  const { data, error } = await supabase
    .from('user_preferences')
    .select('*')
    .eq('user_id', userId)
    .maybeSingle();

  if (error) throw error;
  return data;
}

export async function updateUserPreferences(
  userId: string,
  customFeedTypes: string[]
): Promise&lt;UserPreferences&gt; {
  const { data, error } = await supabase
    .from('user_preferences')
    .upsert({
      user_id: userId,
      custom_feed_types: customFeedTypes,
      updated_at: new Date().toISOString(),
    })
    .select()
    .single();

  if (error) throw error;
  return data;
}

export async function followUser(followerId: string, followingId: string): Promise&lt;void&gt; {
  const { error } = await supabase
    .from('follows')
    .insert({
      follower_id: followerId,
      following_id: followingId,
    });

  if (error) throw error;
}

export async function unfollowUser(followerId: string, followingId: string): Promise&lt;void&gt; {
  const { error } = await supabase
    .from('follows')
    .delete()
    .eq('follower_id', followerId)
    .eq('following_id', followingId);

  if (error) throw error;
}

export async function isFollowing(followerId: string, followingId: string): Promise&lt;boolean&gt; {
  const { data, error } = await supabase
    .from('follows')
    .select('*')
    .eq('follower_id', followerId)
    .eq('following_id', followingId)
    .maybeSingle();

  if (error) throw error;
  return !!data;
}

export async function getFollowing(userId: string): Promise&lt;string[]&gt; {
  const { data, error } = await supabase
    .from('follows')
    .select('following_id')
    .eq('follower_id', userId);

  if (error) throw error;
  return data.map(f =&gt; f.following_id);
}

/* # Initial Schema for Ilham Platform
## New Tables
### `profiles` - `id` (uuid, primary key, references auth.users) - `username` (text, unique, max 40 characters) - `account_type` (text) - 'designer', 'seeker', or 'general' - `avatar_url` (text) - profile avatar image URL - `banner_url` (text) - profile header banner URL - `bio` (text) - user biography - `social_links` (jsonb) - social media links - `created_at` (timestamptz) - `updated_at` (timestamptz)
### `posts` - `id` (uuid, primary key) - `user_id` (uuid, references profiles) - `post_type` (text) - 'my_design', 'design_offer', 'design_request', 'general' - `description` (text, max 300 characters) - `hashtags` (text array, max 5) - `images` (jsonb) - array of image URLs - `created_at` (timestamptz) - `updated_at` (timestamptz)
### `comments` - `id` (uuid, primary key) - `post_id` (uuid, references posts) - `user_id` (uuid, references profiles) - `parent_id` (uuid, references comments) - for replies - `content` (text) - `created_at` (timestamptz) - `updated_at` (timestamptz)
## Security - Enable RLS on all tables - Add policies for authenticated users */
-- Create profiles table CREATE TABLE IF NOT EXISTS profiles ( id uuid PRIMARY KEY REFERENCES auth.users(id) ON DELETE CASCADE, username text UNIQUE NOT NULL, account_type text NOT NULL CHECK (account_type IN ('designer', 'seeker', 'general')), avatar_url text, banner_url text, bio text, social_links jsonb DEFAULT '{}', created_at timestamptz DEFAULT now(), updated_at timestamptz DEFAULT now(), CONSTRAINT username_length CHECK (char_length(username) &lt;= 40) );
-- Create posts table CREATE TABLE IF NOT EXISTS posts ( id uuid PRIMARY KEY DEFAULT gen_random_uuid(), user_id uuid NOT NULL REFERENCES profiles(id) ON DELETE CASCADE, post_type text NOT NULL CHECK (post_type IN ('my_design', 'design_offer', 'design_request', 'general')), description text NOT NULL, hashtags text[] DEFAULT '{}', images jsonb DEFAULT '[]', created_at timestamptz DEFAULT now(), updated_at timestamptz DEFAULT now(), CONSTRAINT description_length CHECK (char_length(description) &lt;= 300), CONSTRAINT hashtags_limit CHECK (array_length(hashtags, 1) &lt;= 5), CONSTRAINT images_limit CHECK (jsonb_array_length(images) &lt;= 15) );
-- Create comments table CREATE TABLE IF NOT EXISTS comments ( id uuid PRIMARY KEY DEFAULT gen_random_uuid(), post_id uuid NOT NULL REFERENCES posts(id) ON DELETE CASCADE, user_id uuid NOT NULL REFERENCES profiles(id) ON DELETE CASCADE, parent_id uuid REFERENCES comments(id) ON DELETE CASCADE, content text NOT NULL, created_at timestamptz DEFAULT now(), updated_at timestamptz DEFAULT now() );
-- Create indexes for better performance CREATE INDEX IF NOT EXISTS idx_posts_user_id ON posts(user_id); CREATE INDEX IF NOT EXISTS idx_posts_created_at ON posts(created_at DESC); CREATE INDEX IF NOT EXISTS idx_comments_post_id ON comments(post_id); CREATE INDEX IF NOT EXISTS idx_comments_parent_id ON comments(parent_id);
-- Enable RLS ALTER TABLE profiles ENABLE ROW LEVEL SECURITY; ALTER TABLE posts ENABLE ROW LEVEL SECURITY; ALTER TABLE comments ENABLE ROW LEVEL SECURITY;
-- Profiles policies CREATE POLICY "Public profiles are viewable by everyone" ON profiles FOR SELECT TO authenticated USING (true);
CREATE POLICY "Users can insert their own profile" ON profiles FOR INSERT TO authenticated WITH CHECK (auth.uid() = id);
CREATE POLICY "Users can update their own profile" ON profiles FOR UPDATE TO authenticated USING (auth.uid() = id) WITH CHECK (auth.uid() = id);
-- Posts policies CREATE POLICY "Posts are viewable by everyone" ON posts FOR SELECT TO authenticated USING (true);
CREATE POLICY "Users can create their own posts" ON posts FOR INSERT TO authenticated WITH CHECK (auth.uid() = user_id);
CREATE POLICY "Users can update their own posts" ON posts FOR UPDATE TO authenticated USING (auth.uid() = user_id) WITH CHECK (auth.uid() = user_id);
CREATE POLICY "Users can delete their own posts" ON posts FOR DELETE TO authenticated USING (auth.uid() = user_id);
-- Comments policies CREATE POLICY "Comments are viewable by everyone" ON comments FOR SELECT TO authenticated USING (true);
CREATE POLICY "Users can create comments" ON comments FOR INSERT TO authenticated WITH CHECK (auth.uid() = user_id);
CREATE POLICY "Users can update their own comments" ON comments FOR UPDATE TO authenticated USING (auth.uid() = user_id) WITH CHECK (auth.uid() = user_id);
CREATE POLICY "Users can delete their own comments" ON comments FOR DELETE TO authenticated USING (auth.uid() = user_id);

