export interface Ad {
  id: string;
  title: string;
  description: string;
  image_url: string | null;
  link_url: string | null;
  is_pinned: boolean;
  impressions_limit: number;
  impressions_count: number;
  clicks_count: number;
  start_date: string;
  end_date: string | null;
  is_active: boolean;
  created_at: string;
}

export interface AdClick {
  id: string;
  ad_id: string;
  user_id: string | null;
  clicked_at: string;
}

export interface CreateAdInput {
  title: string;
  description: string;
  image_url?: string;
  link_url?: string;
  is_pinned?: boolean;
  impressions_limit?: number;
  start_date?: string;
  end_date?: string;
}

import { PostType } from './post';

export type FeedTab = 'custom' | 'general' | 'design' | 'request' | 'offer' | 'following';

export interface FeedParams {
  tab: FeedTab;
  userId: string;
  preferences?: string[];
  page?: number;
  limit?: number;
}

export interface FeedItem {
  id: string;
  type: 'post' | 'ad';
  data: any;
}

export interface PaginationMeta {
  page: number;
  limit: number;
  hasMore: boolean;
  total?: number;
}

export interface FeedResponse {
  items: FeedItem[];
  meta: PaginationMeta;
}

export type PostType = 'general' | 'design' | 'request' | 'offer' | 'attachment';
export type PostStatus = 'open' | 'closed' | 'completed';

export interface Post {
  id: string;
  user_id: string;
  type: PostType;
  status: PostStatus;
  title: string | null;
  description: string;
  images: string[];
  attachments: Attachment[];
  price: number | null;
  likes_count: number;
  comments_count: number;
  views_count: number;
  created_at: string;
  updated_at: string;
}

export interface Attachment {
  name: string;
  url: string;
  size?: number;
  type?: string;
}

export interface PostWithUser extends Post {
  user: {
    id: string;
    username: string;
    display_name: string | null;
    avatar_url: string | null;
  };
  is_liked?: boolean;
}

export interface CreatePostInput {
  type: PostType;
  status?: PostStatus;
  title?: string;
  description: string;
  images?: string[];
  attachments?: Attachment[];
  price?: number;
}

export interface UpdatePostInput {
  type?: PostType;
  status?: PostStatus;
  title?: string;
  description?: string;
  images?: string[];
  attachments?: Attachment[];
  price?: number;
}

export interface UserProfile {
  id: string;
  username: string;
  display_name: string | null;
  avatar_url: string | null;
  bio: string | null;
  created_at: string;
  updated_at: string;
}

export interface UpdateUserProfileInput {
  username?: string;
  display_name?: string;
  avatar_url?: string;
  bio?: string;
}

export interface UserPreferences {
  user_id: string;
  custom_feed_types: string[];
  created_at: string;
  updated_at: string;
}

export interface Follow {
  follower_id: string;
  following_id: string;
  created_at: string;
}
